#include <bits/stdc++.h>
using namespace std;
const int N=200005;
int q,a[N],b[N],c[N];
long long num;
int fun(int x,int y)
{
	if(y==2)
	{
		if(x%4==0)
		{
			if(x%100==0)
			{
				if(x%400==0) return 29;
				return 28;
			}
			else return 29;
		}
		else return 28;
	}
	return (y==4||y==6||y==9||y==11)?30:31;
}
int main()
{
//	freopen("julian3.in","r",stdin);
//	freopen("julian3.out","w",stdout);
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	b[0]=c[0]=1;
	for(int i=1;i<150000;i++)
	{
		c[i]=c[i-1]+1;
		b[i]=b[i-1];
		a[i]=a[i-1];
		if(c[i]>fun(a[i],b[i]))
		{
			b[i]++;
			c[i]=1;
		}
		if(b[i]>12)
		{
			b[i]=1;
			a[i]++;
		}
	}
	cin>>q;
	while(q--)
	{
		long long tmp;
		cin>>num;
		if(num>2299160)
		{
			num-=2159351;
			tmp=num/146097*400+1200;
			num%=146097;
		}
		else
		{
			tmp=num/1461*4-4712;
			num%=1461;
		}
//		cout<<tmp<<" "<<a[num]<<"\n";
		if(tmp+a[num]>0) cout<<c[num]<<" "<<b[num]<<" "<<tmp+a[num]<<"\n";
		else cout<<c[num]<<' '<<b[num]<<" "<<1ll-(tmp+a[num])<<" BC\n";
	}
	return 0;
}
